// Helper: filter services by category slug
export function getServicesByCategory(slug: string): ServiceItem[] {
  if (!slug || slug === 'all') return ALL_SERVICES
  return ALL_SERVICES.filter(s => s.categorySlug === slug)
}

// Helper: search services
export function searchServices(query: string): ServiceItem[] {
  const q = query.trim().toLowerCase()
  if (!q) return ALL_SERVICES
  return ALL_SERVICES.filter(s =>
    s.name_ar.includes(q) ||
    s.category.includes(q) ||
    s.authority_ar.includes(q) ||
    s.description.includes(q)
  )
}